                <div class="control-group">
                    <div class="control-label">
                        <span>参数 a (二次项系数)</span>
                        <span class="param-value" id="a-value">1</span>
                    </div>
                    <input type="range" id="a-slider" min="-5" max="5" step="0.1" value="1">
                </div>

                <div class="control-group">
                    <div class="control-label">
                        <span>参数 b (一次项系数)</span>
                        <span class="param-value" id="b-value">-2</span>
                    </div>
                    <input type="range" id="b-slider" min="-5" max="5" step="0.1" value="-2">
                </div>

                <div class="control-group">
                    <div class="control-label">
                        <span>参数 c (常数项)</span>
                        <span class="param-value" id="c-value">-3</span>
                    </div>
                    <input type="range" id="c-slider" min="-5" max="5" step="0.1" value="-3">
                </div>

                <div class="button-group">
