    <script>
        const canvas = document.getElementById('canvas');
        const ctx = canvas.getContext('2d');
        const tooltip = document.getElementById('tooltip');

        let a = 1, b = -2, c = -3;
        let scale = 40;
        let offsetX = canvas.width / 2;
        let offsetY = canvas.height / 2;
        let isDragging = false;
        let dragStartX = 0;
        let dragStartY = 0;

        // 正确的参数值 (a=-1, b=2, c=3) - 题目答案
        const correctA = -1, correctB = 2, correctC = 3;

        function drawGrid() {
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // 绘制网格
            ctx.strokeStyle = '#e0e0e0';
            ctx.lineWidth = 1;

            for (let x = 0; x <= canvas.width; x += scale) {
                ctx.beginPath();
                ctx.moveTo(x, 0);
                ctx.lineTo(x, canvas.height);
                ctx.stroke();
            }

            for (let y = 0; y <= canvas.height; y += scale) {
                ctx.beginPath();
                ctx.moveTo(0, y);
                ctx.lineTo(canvas.width, y);
                ctx.stroke();
            }

            // 绘制坐标轴
            ctx.strokeStyle = '#333';
            ctx.lineWidth = 2;

            // X轴
            ctx.beginPath();
            ctx.moveTo(0, offsetY);
            ctx.lineTo(canvas.width, offsetY);
            ctx.stroke();

            // Y轴
            ctx.beginPath();
            ctx.moveTo(offsetX, 0);
            ctx.lineTo(offsetX, canvas.height);
            ctx.stroke();

            // 绘制刻度
            ctx.fillStyle = '#666';
            ctx.font = '12px Arial';
            ctx.textAlign = 'center';

            for (let i = -6; i <= 6; i++) {
                if (i !== 0) {
                    ctx.fillText(i.toString(), offsetX + i * scale, offsetY + 20);
                }
            }

            ctx.textAlign = 'right';
            for (let i = -4; i <= 4; i++) {
                if (i !== 0) {
                    ctx.fillText((-i).toString(), offsetX - 10, offsetY + i * scale + 5);
                }
            }

            ctx.fillText('O', offsetX - 15, offsetY + 20);
            ctx.fillText('x', canvas.width - 15, offsetY + 20);

            ctx.textAlign = 'left';
            ctx.fillText('y', offsetX + 10, 15);
        }

        function drawParabola() {
            ctx.strokeStyle = '#667eea';
            ctx.lineWidth = 3;
            ctx.beginPath();

            let firstPoint = true;

            for (let px = 0; px <= canvas.width; px += 1) {
                const x = (px - offsetX) / scale;
                const y = a * x * x + b * x + c;
                const py = offsetY - y * scale;

                if (py >= -100 && py <= canvas.height + 100) {
                    if (firstPoint) {
                        ctx.moveTo(px, py);
                        firstPoint = false;
                    } else {
                        ctx.lineTo(px, py);
                    }
                }
            }

            ctx.stroke();

            // 绘制抛物线上的三个已知点（当参数正确时）
            if (Math.abs(a - correctA) < 0.1 && Math.abs(b - correctB) < 0.1 && Math.abs(c - correctC) < 0.1) {
                const points = [
                    {x: -1, y: 0, label: 'A'},
                    {x: 3, y: 0, label: 'B'},
                    {x: 0, y: 3, label: 'C'}
                ];

                points.forEach(p => {
                    const px = offsetX + p.x * scale;
                    const py = offsetY - p.y * scale;

                    ctx.fillStyle = '#eb3349';
                    ctx.beginPath();
                    ctx.arc(px, py, 6, 0, Math.PI * 2);
                    ctx.fill();

                    ctx.fillStyle = '#333';
                    ctx.font = 'bold 14px Arial';
                    ctx.fillText(p.label, px + 10, py - 10);
                });
            }

            // 绘制顶点
            const vx = -b / (2 * a);
            const vy = c - b * b / (4 * a);
            const vpx = offsetX + vx * scale;
            const vpy = offsetY - vy * scale;

            if (vpx > 0 && vpx < canvas.width && vpy > 0 && vpy < canvas.height) {
                ctx.fillStyle = '#38ef7d';
                ctx.beginPath();
                ctx.arc(vpx, vpy, 8, 0, Math.PI * 2);
                ctx.fill();

                ctx.fillStyle = '#333';
                ctx.font = 'bold 12px Arial';
                ctx.fillText(`(${vx.toFixed(2)}, ${vy.toFixed(2)})`, vpx + 15, vpy - 15);
            }

            // 绘制顶点可拖动标示
            if (vpx > 0 && vpx < canvas.width && vpy > 0 && vpy < canvas.height) {
                ctx.strokeStyle = '#38ef7d';
                ctx.lineWidth = 2;
                ctx.setLineDash([5, 5]);
                ctx.beginPath();
                ctx.arc(vpx, vpy, 15, 0, Math.PI * 2);
                ctx.stroke();
                ctx.setLineDash([]);
            }

            // 绘制对称轴
            ctx.strokeStyle = 'rgba(102, 126, 234, 0.3)';
            ctx.lineWidth = 2;
            ctx.setLineDash([5, 5]);
            ctx.beginPath();
            ctx.moveTo(vpx, 0);
            ctx.lineTo(vpx, canvas.height);
            ctx.stroke();
            ctx.setLineDash([]);
        }

        function updateDisplay() {
            document.getElementById('equation-text').textContent = 
                `y = ${a > 0 && Math.abs(a - 1) < 0.1 ? '' : a < 0 && Math.abs(a + 1) < 0.1 ? '-' : a.toFixed(1)}x² ${b > 0 ? '+' : ''}${Math.abs(b) < 0.01 ? '' : (Math.abs(b - 1) < 0.1 ? '' : b.toFixed(1)) + 'x '}${c > 0 ? '+' : ''}${c.toFixed(1)}`;

            document.getElementById('direction').textContent = a > 0 ? '向上开口' : '向下开口';
            document.getElementById('direction').style.color = a > 0 ? '#38ef7d' : '#eb3349';

            const vx = -b / (2 * a);
            document.getElementById('axis').textContent = `x = ${vx.toFixed(2)}`;

            const vy = c - b * b / (4 * a);
            document.getElementById('vertex').textContent = `(${vx.toFixed(2)}, ${vy.toFixed(2)})`;

            drawGrid();
            drawParabola();
        }

        function updateSlider(id, value) {
            document.getElementById(id).value = value;
            document.getElementById(id.replace('-slider', '-value')).textContent = parseFloat(value).toFixed(1);
        }

        document.getElementById('a-slider').addEventListener('input', (e) => {
            a = parseFloat(e.target.value);
            updateSlider('a-slider', a);
            updateDisplay();
        });

        document.getElementById('b-slider').addEventListener('input', (e) => {
            b = parseFloat(e.target.value);
            updateSlider('b-slider', b);
            updateDisplay();
        });

        document.getElementById('c-slider').addEventListener('input', (e) => {
            c = parseFloat(e.target.value);
            updateSlider('c-slider', c);
            updateDisplay();
        });

        // 鼠标拖拽顶点
        canvas.addEventListener('mousedown', (e) => {
            const rect = canvas.getBoundingClientRect();
            const mouseX = e.clientX - rect.left;
            const mouseY = e.clientY - rect.top;

            const vx = -b / (2 * a);
            const vy = c - b * b / (4 * a);
            const vpx = offsetX + vx * scale;
            const vpy = offsetY - vy * scale;

            const dist = Math.sqrt((mouseX - vpx) ** 2 + (mouseY - vpy) ** 2);

            if (dist < 20) {
