            }
        });

        canvas.addEventListener('mousemove', (e) => {
            const rect = canvas.getBoundingClientRect();
            const mouseX = e.clientX - rect.left;
            const mouseY = e.clientY - rect.top;

            // 显示坐标 tooltip
            const x = (mouseX - offsetX) / scale;
            const y = (offsetY - mouseY) / scale;
            tooltip.style.display = 'block';
            tooltip.style.left = (e.clientX + 10) + 'px';
            tooltip.style.top = (e.clientY - 30) + 'px';
            tooltip.textContent = `(${x.toFixed(2)}, ${y.toFixed(2)})`;

            if (isDragging) {
                const newX = (mouseX - offsetX) / scale;
                const newY = (offsetY - mouseY) / scale;

                // 根据新顶点位置更新 b 和 c
                b = -2 * a * newX;
                c = newY + a * newX * newX;

                updateSlider('b-slider', b);
                updateSlider('c-slider', c);
                updateDisplay();
            }

            // 检测是否悬停在顶点上
            const vx = -b / (2 * a);
            const vy = c - b * b / (4 * a);
            const vpx = offsetX + vx * scale;
            const vpy = offsetY - vy * scale;
            const dist = Math.sqrt((mouseX - vpx) ** 2 + (mouseY - vpy) ** 2);

            if (dist < 20 && !isDragging) {
                canvas.style.cursor = 'grab';
            } else if (!isDragging) {
                canvas.style.cursor = 'crosshair';
            }
        });

        canvas.addEventListener('mouseup', () => {
            isDragging = false;
            canvas.style.cursor = 'crosshair';
        });

        canvas.addEventListener('mouseleave', () => {
            isDragging = false;
            canvas.style.cursor = 'crosshair';
            tooltip.style.display = 'none';
        });

        function resetToAnswer() {
            a = correctA;
            b = correctB;
            c = correctC;

            updateSlider('a-slider', a);
            updateSlider('b-slider', b);
            updateSlider('c-slider', c);
            updateDisplay();

            // 隐藏所有步骤
            document.querySelectorAll('.solution-step').forEach(step => {
                step.classList.remove('show');
            });
        }

        let currentStep = 0;
        function showNextStep() {
            currentStep++;
            if (currentStep > 3) {
                currentStep = 0;
                document.querySelectorAll('.solution-step').forEach(step => {
                    step.classList.remove('show');
                });
                return;
            }

            const step = document.querySelector(`.solution-step[data-step="${currentStep}"]`);
            if (step) {
                step.classList.add('show');
                step.scrollIntoView({ behavior: 'smooth', block: 'center' });
            }
        }

        function checkAnswer(element) {
            const value = parseFloat(element.dataset.value);
            const resultDiv = document.getElementById('quiz-result');
            const options = document.querySelectorAll('.quiz-option');

            // 先重置所有选项区域
            options.forEach(opt => {
                opt.classList.remove('correct', 'wrong');
                opt.style.pointerEvents = 'none';
            });

            // 正确答案的交互反馈
            if (value === 3) {
                element.classList.add('correct');
                resultDiv.innerHTML = '🎉 <span style="color: #11998e;">恭喜你答对了！当 x = 2 时，y = -(2)² + 2(2) + 3 = -4 + 4 + 3 = 3</span>';
            } else {
                element.classList.add('wrong');
                resultDiv.innerHTML = '❌ <span style="color: #eb3349;">答错了。再算一遍：y = -(2)² + 2(2) + 3 = -4 + 4 + 3 = 3，答案是 A</span>';
            }

            // 高亮正确答案
            options.forEach(opt => {
                if (parseFloat(opt.dataset.value) === 3) {
                    opt.classList.add('correct');
                }
            });
        }

        // 初始化
        updateDisplay();

        // 将函数暴露到全局作用域
        window.resetToAnswer = resetToAnswer;
        window.showNextStep = showNextStep;
        window.checkAnswer = checkAnswer;
    </script>
